para.programlisting:
CREATE TABLE gold_acquisitions.dim_defendants (
  defendant_id         STRING  NOT NULL,
  defendant_name_token STRING,            -- TOKENIZED — PII
  defendant_role       STRING,
  case_id              STRING             -- denormalized for convenience
);

section.programlisting:
# Bronze bucket with lifecycle management
resource "google_storage_bucket" "bronze" {
  name          = "${var.project_id}-bronze-${var.environment}"
  location      = var.region
  storage_class = "STANDARD"

  versioning { enabled = true }

  lifecycle_rule {
    condition { age = 90 }
    action    { type          = "SetStorageClass"
                storage_class = "NEARLINE" }
  }

  lifecycle_rule {
    condition { age = 2555 }   # 7 years
    action    { type = "Delete" }
  }

  encryption {
    default_kms_key_name = var.kms_key_id
  }
}

para.programlisting:
config { type: "incremental", schema: "silver_acquisitions", name: "cases", tags: ["acquisitions", "silver"], description: "Deduplicated, type-cast court case records. PK: case_id.", }
SELECT case_id, TRIM(case_name) AS case_name, UPPER(TRIM(court_district)) AS court_district, PARSE_DATE('%m/%d/%Y', filing_date) AS filing_date, CASE WHEN UPPER(status) IN ('ACTIVE','OPEN','FILED') THEN 'ACTIVE' WHEN UPPER(status) IN ('SETTLED','CLOSED') THEN 'SETTLED' WHEN UPPER(status) IN ('DISMISSED','DROPPED') THEN 'DISMISSED' ELSE 'UNKNOWN' END AS status, _ingested_at AS _bronze_ingested_at, CURRENT_TIMESTAMP() AS _created_at, CURRENT_TIMESTAMP() AS _updated_at
FROM ${ref("bronze_acquisitions", "cases_raw")} WHERE case_id IS NOT NULL AND filing_date IS NOT NULL
${ when(incremental(), ` AND DATE(_ingested_at) > ( SELECT MAX(DATE(_bronze_ingested_at)) FROM ${self()} ) `) }
QUALIFY ROW_NUMBER() OVER ( PARTITION BY case_id ORDER BY _ingested_at DESC ) = 1

config { type: "incremental", schema: "silver_acquisitions", name: "properties", tags: ["acquisitions", "silver"], description: "Cleaned, type-cast property records. FK: case_id → cases.", }
SELECT GENERATE_UUID() AS property_id, case_id, TRIM(parcel_id) AS parcel_id, TRIM(address_raw) AS street_address, REGEXP_EXTRACT(address_raw, r'^(.*?),\s*[A-Z]{2}\s+\d{5}') AS city, REGEXP_EXTRACT(address_raw, r',\s*([A-Z]{2})\s+\d{5}') AS state, REGEXP_EXTRACT(address_raw, r'(\d{5})(?:-\d{4})?$') AS zip_code, TRIM(owner_name_raw) AS owner_name, SAFE_CAST( REPLACE(REPLACE(assessed_value_raw, '$', ''), ',', '') AS NUMERIC ) AS assessed_value, SAFE_CAST(TRIM(tax_year_raw) AS INT64) AS tax_year, SAFE_CAST( REPLACE(REPLACE(delinquent_amount_raw, '$', ''), ',', '') AS NUMERIC ) AS delinquent_amount, latitude, longitude, CURRENT_TIMESTAMP() AS _created_at, CURRENT_TIMESTAMP() AS _updated_at
FROM ${ref("bronze_acquisitions", "properties_raw")} WHERE case_id IS NOT NULL
${ when(incremental(), ` AND DATE(_ingested_at) > (SELECT MAX(DATE(_created_at)) FROM ${self()}) `) }
QUALIFY ROW_NUMBER() OVER ( PARTITION BY case_id, COALESCE(parcel_id, address_raw) ORDER BY _ingested_at DESC ) = 1

config { type: "incremental", schema: "silver_acquisitions", name: "defendants", tags: ["acquisitions", "silver"], description: "Defendant records extracted from Bronze PDFs. PII tokenized. FK: case_id → cases.", }
SELECT GENERATE_UUID() AS defendant_id, case_id, -- SHA-256 token. Raw defendant name is retained in bronze_acquisitions.defendants_raw only. TO_HEX(SHA256(LOWER(TRIM(defendant_name_extracted)))) AS defendant_name_token, COALESCE(UPPER(TRIM(defendant_role_extracted)), 'UNKNOWN') AS defendant_role, extraction_confidence, _source_pdf, CURRENT_TIMESTAMP() AS _created_at, CURRENT_TIMESTAMP() AS _updated_at
FROM ${ref("bronze_acquisitions", "defendants_raw")} WHERE case_id IS NOT NULL AND defendant_name_extracted IS NOT NULL AND extraction_confidence >= 0.5 -- exclude low-confidence extractions from Silver
${ when(incremental(), ` AND DATE(_ingested_at) > (SELECT MAX(DATE(_created_at)) FROM ${self()}) `) }
QUALIFY ROW_NUMBER() OVER ( PARTITION BY case_id, TO_HEX(SHA256(LOWER(TRIM(defendant_name_extracted)))) ORDER BY extraction_confidence DESC ) = 1

config { type: "incremental", schema: "gold_acquisitions", name: "fact_distressed_acquisitions", tags: ["acquisitions", "gold", "star-schema"], description: "Fact table for distressed acquisition analysis. Grain: case × property × defendant.", }
SELECT GENERATE_UUID() AS fact_id, c.case_id, p.property_id, d.defendant_id, p.delinquent_amount, p.assessed_value, p.tax_year, DATE_DIFF(CURRENT_DATE(), c.filing_date, DAY) AS days_since_filing, -- Acquisition score: composite heuristic (0–100) -- Higher delinquency ratio + longer time filed = higher score ROUND(LEAST(100, (p.delinquent_amount / NULLIF(p.assessed_value, 0)) * 50 + LEAST(50, DATE_DIFF(CURRENT_DATE(), c.filing_date, DAY) / 10) ), 2) AS acquisition_score, CURRENT_DATE() AS reporting_date, CURRENT_TIMESTAMP() AS _refreshed_at
FROM ${ref("silver_acquisitions", "cases")} c JOIN ${ref("silver_acquisitions", "properties")} p ON p.case_id = c.case_id JOIN ${ref("silver_acquisitions", "defendants")} d ON d.case_id = c.case_id WHERE c.status = 'ACTIVE'
${ when(incremental(), ` AND c._updated_at > (SELECT MAX(_refreshed_at) FROM ${self()}) `) }

config { type: "incremental", schema: "gold_acquisitions", name: "crm_distressed_export", tags: ["acquisitions", "gold", "crm", "obt"], description: "Pre-joined One Big Table for CRM integration. One flat row per case/property/defendant.", }
SELECT -- Case c.case_id, c.case_name, c.court_district, c.filing_date, c.status AS case_status, DATE_DIFF(CURRENT_DATE(), c.filing_date, DAY) AS days_since_filing, -- Property p.parcel_id, CONCAT( COALESCE(p.street_address,''), ', ', COALESCE(p.city,''), ', ', COALESCE(p.state,''), ' ', COALESCE(p.zip_code,'') ) AS property_address, p.city AS property_city, p.state AS property_state, p.zip_code AS property_zip, p.assessed_value, p.delinquent_amount, p.tax_year, p.latitude, p.longitude, -- Defendant (PII tokenized — raw name stays in Bronze only) d.defendant_name_token, d.defendant_role, -- Scoring ROUND(LEAST(100, (p.delinquent_amount / NULLIF(p.assessed_value, 0)) * 50 + LEAST(50, DATE_DIFF(CURRENT_DATE(), c.filing_date, DAY) / 10) ), 2) AS acquisition_score, -- CRM sync control CURRENT_TIMESTAMP() AS export_prepared_at, 'NEW' AS crm_sync_status
FROM ${ref("silver_acquisitions", "cases")} c JOIN ${ref("silver_acquisitions", "properties")} p ON p.case_id = c.case_id JOIN ${ref("silver_acquisitions", "defendants")} d ON d.case_id = c.case_id WHERE c.status = 'ACTIVE'
${ when(incremental(), ` AND c._updated_at > (SELECT MAX(export_prepared_at) FROM ${self()}) `) }
